#include<bits/stdc++.h>
using namespace std;
struct node
{
    int t1,t2;
    bool operator<(const node&b)const
    {
        return t2<b.t2;
    }
}a[150010];
priority_queue<long long> q;
long long sum,ans;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].t1,&a[i].t2);
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        sum+=a[i].t1;
        q.push(a[i].t1);
        if(sum<=a[i].t2)
        {
            ans++;
        }
        else
        {
            sum-=q.top();
            q.pop();
        }
    }
    printf("%lld",ans);
    return 0;
}
